36	export const Action: React.FC<{
37	  scene: ActionScene;
38	  caption?: string;
39	  durationInFrames: number;
40	}> = ({ scene, caption, durationInFrames }) => {
41	  const frame = useCurrentFrame();
42	  const { height, fps } = useVideoConfig();
43	
44	  // Every chip must land within the stream window regardless of event count —
45	  // pacing fits the scene's duration budget, never the other way around.
46	  const streamFrames = durationInFrames * (scene.intensity === "montage" ? 0.75 : 0.9);
47	  const interval = Math.max(1.5, (streamFrames - 10) / scene.events.length);
48	  const slideDur = Math.min(12, Math.max(3, interval));
49	
50	  // One progress evaluation per chip per frame, shared by scroll and render.
51	  const progresses = scene.events.map((_e, i) =>
52	    interpolate(frame, [10 + i * interval, 10 + i * interval + slideDur], [0, 1], {
53	      easing: Easing.bezier(0.16, 1, 0.3, 1),
54	      extrapolateLeft: "clamp",
55	      extrapolateRight: "clamp",
56	    }),
57	  );
58	
59	  // Every chip that lands pushes the whole stack up by one slot.
60	  const scrollUp = progresses.reduce((acc, p) => acc + p, 0);
